INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd4d2049-361e-42b6-963c-bdfb79c1fc26',
  '00000000-0000-0000-0000-000000000001',
  $escape$Python's Execution Model — CPython Bytecode, PyPy JIT, and Cold Start Costs$escape$,
  $escape$CPython doesn't compile to native machine code — it compiles your `.py` files to bytecode (`.pyc` in `__pycache__`), then the CPython VM interprets that bytecode at runtime. This interpretation loop is the core reason Python is slower than Go or Rust for CPU-bound work. Each opcode is dispatched individually, with no runtime optimization based on actual execution paths.

PyPy changes this with a tracing JIT: it observes hot loops at runtime and compiles them to native code on the fly. A tight numeric loop can run 10–50x faster under PyPy versus CPython — but PyPy has a warm-up cost before JIT kicks in, making it a poor fit for short-lived scripts.

Cold start matters in serverless (AWS Lambda, GCP Cloud Functions). A CPython process importing `numpy`, `pandas`, or `boto3` can take 800ms–2s before executing a single line of your handler. Strategies: use Lambda SnapStart, keep dependencies minimal, or switch to a lighter runtime image. `python -X importtime -c 'import boto3'` reveals per-module import cost directly.$escape$,
  $escape$import sys
import time

# See bytecode CPython generates
import dis

def add(a, b):
    return a + b

dis.dis(add)
# Outputs opcodes: LOAD_FAST, BINARY_OP, RETURN_VALUE

# Measure cold import cost manually
start = time.perf_counter()
import json  # swap with boto3, numpy, etc.
elapsed = time.perf_counter() - start
print(f"Import took {elapsed * 1000:.2f}ms")

# CLI: python -X importtime -c 'import boto3' 2>&1 | sort -k2 -rn | head -10$escape$,
  $escape$python$escape$,
