INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a7f3c509-1c3d-4da6-bd71-3961674a7ebe',
  '00000000-0000-0000-0000-000000000001',
  $escape$Python Security — Memory Safety, Injection Prevention, and Dependency Scanning$escape$,
  $escape$Python's managed memory model eliminates buffer overflows, but you still face injection risks and vulnerable dependencies. For SQL, never use f-strings or %-formatting with user input — always use parameterized queries via `psycopg2` or SQLAlchemy's bound parameters. For shell commands, avoid `subprocess.run(shell=True)` with user-controlled strings; pass a list instead to bypass shell interpolation. Deserialization is a silent attack vector: `pickle.loads()` on untrusted data executes arbitrary code — prefer `json.loads()` for external payloads. On the dependency side, run `pip-audit` (wraps OSV and PyPI Advisory DB) in CI to catch known CVEs in your `requirements.txt` or `pyproject.toml`. Pair it with `safety check` for a second opinion. Pin dependencies with hashes using `pip install --require-hashes` to prevent supply-chain substitution attacks. For secrets, never hardcode — use `python-dotenv` locally and environment injection in production, and scan commits with `detect-secrets` pre-commit hook to catch leaks before they reach origin.$escape$,
  $escape$import subprocess
import psycopg2
import json

# UNSAFE — shell=True with user input
# subprocess.run(f"ls {user_input}", shell=True)

# SAFE — list form bypasses shell interpolation
subprocess.run(["ls", user_input], check=True)

# UNSAFE — f-string SQL
# cursor.execute(f"SELECT * FROM users WHERE id = {user_id}")

# SAFE — parameterized query
cursor.execute("SELECT * FROM users WHERE id = %s", (user_id,))

# UNSAFE — pickle on untrusted data
# obj = pickle.loads(untrusted_bytes)

# SAFE — JSON for external payloads
obj = json.loads(untrusted_string)$escape$,
  $escape$python$escape$,
